<?php require_once __DIR__ . '/includes/layout.php'; render_header('All Tools'); $qstr=$_GET['q']??''; $tools=q('SELECT t.*, c.name category FROM tools t LEFT JOIN categories c ON c.id=t.category_id WHERE t.status="published" AND (t.name LIKE ? OR t.description LIKE ?) ORDER BY t.sort_order,t.name',["%$qstr%","%$qstr%"])->fetchAll(); ?>
<main class="container section"><p class="eyebrow">All tools</p><h1>Find the right creator tool</h1><form><input class="input" name="q" value="<?= e($qstr) ?>" placeholder="Search tools..."></form><div class="grid-auto" style="margin-top:20px"><?php foreach($tools as $tool): ?><a class="card tool-card" href="/tool.php?slug=<?= e($tool['slug']) ?>"><span class="icon"><?= e(substr($tool['name'],0,2)) ?></span><p class="eyebrow"><?= e($tool['category']) ?></p><h3><?= e($tool['name']) ?></h3><p class="muted"><?= e($tool['description']) ?></p></a><?php endforeach; ?></div></main><?php render_footer(); ?>
